interface ReplayCache {
    boolean putIfAbsent(String key, Instant expiresAt);
}

class InMemoryReplayCache implements ReplayCache {

    private final ConcurrentHashMap<String, Long> map = new ConcurrentHashMap<>();
    private final Duration cleanupInterval;
    private volatile long lastCleanupNanos = System.nanoTime();

    InMemoryReplayCache(Duration cleanupInterval) {
        this.cleanupInterval = cleanupInterval != null ? cleanupInterval : Duration.ofMinutes(1);
    }

    @Override
    public boolean putIfAbsent(String key, Instant expiresAt) {
        long exp = expiresAt.toEpochMilli();
        cleanupIfNeeded();
        Long prev = map.putIfAbsent(key, exp);
        if (prev == null) return true;
        // If existing entry expired, allow replacement
        if (prev < System.currentTimeMillis()) {
            map.remove(key, prev);
            prev = map.putIfAbsent(key, exp);
            return prev == null;
        }
        return false;
    }

    private void cleanupIfNeeded() {
        long nowNanos = System.nanoTime();
        long intervalNanos = cleanupInterval.toNanos();
        if (nowNanos - lastCleanupNanos < intervalNanos) return;
        synchronized (this) {
            nowNanos = System.nanoTime();
            if (nowNanos - lastCleanupNanos < intervalNanos) return;
            long nowMs = System.currentTimeMillis();
            for (Map.Entry<String, Long> e : map.entrySet()) {
                if (e.getValue() < nowMs) map.remove(e.getKey(), e.getValue());
            }
            lastCleanupNanos = nowNanos;
        }
    }
}

